var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시간이 없어! 어떻게든 하지 않으면......!","JPN":"時間がない！　どうにかしないと……！","ENG":"We're running out of time! We must do something, or...","TWN":"沒時間了！再不想辦法的話……！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면...... 비숍을 먼저 처리하세요.","JPN":"でしたら……ビショップを先に片づけてください。","ENG":"Then... you should take care of Bishop first.","TWN":"那就……先處理主教吧。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 어떻게든 틈을 만들어 볼게요.","JPN":"僕がどうにか隙を作ってみますから。","ENG":"I'll try to create an opening.","TWN":"我會想辦法幫妳製造機會。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무, 무슨 소리야? 우리의 적은 리플레이서 킹이라고. 그런데 비숍은 왜......?","JPN":"ど、どういうこと？　私たちの敵はリプレイサー・キングでしょ？　ビショップはどうして……？","ENG":"W-what are you talking about? Replacer King is the our archenemy here. Why Bishop, all of a sudden?","TWN":"你、你在說什麼？我們的敵人是克隆．帝皇啊。為什麼要處理主教……？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 스승님이 미나 양에게 테라사이드 시스템의 중추를 파괴하라고 했죠?","JPN":"ミナさん、師匠にテラサイドシステムの中枢を破壊するように言われたんですよね？","ENG":"Mina, Master told you to destroy the backbone of System Terraside, didn't she?","TWN":"米娜小姐，師父要妳破壞特拉賽德系統的中樞吧？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아, 하지만 그건 불멸체 코어를 이야기하는 거잖아?","JPN":"うん、でもそれは不滅体コアのことでしょ？","ENG":"She did, but wasn't it the Immortal System Core that she was talking about?","TWN":"是啊，但那不是在說不滅者核心嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 퀸이나 다른 간부들을 재생시키는......","JPN":"リプレイサー・クイーンや他の幹部を再生するための……","ENG":"That's the one regenerating the Queen and other officers...","TWN":"讓克隆·女皇和其他幹部再生的……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇지 않아요.","JPN":"いいえ。","ENG":"You're mistaken.","TWN":"不是的。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물론 불멸체 코어도 테라사이드 시스템의 주요 하부 시스템이긴 하지만, 그게 중추라고는 할 수 없죠.","JPN":"もちろん、不滅体コアもテラサイドシステムの主なシステムの一つですが、それが中枢とは言えません。","ENG":"Of course, the Immortal System Core is also an important part of System Terraside, but it's hardly the backbone.","TWN":"當然，不滅者核心是特拉賽德系統的主要子系統，但它不是中樞。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그건 그저 파괴와 재생을 통해 데이터를 수집하는 역할을 할 뿐,","JPN":"それは単に破壊と再生を通じて、データ収集の役割をするだけで、","ENG":"What it's doing is collect data gained from the process of destruction and regeneration.","TWN":"那只是透過破壞和再生，負責收集資料的東西。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 레플리카 인자를 조합하는 궁극적인 기능은 컨트롤 브레인인 리플레이서 비숍이 담당하고 있어요.","JPN":"レプリカ・クリフォト・ファクターを組み合わせる究極の機能は、\\nコントロールブレーンであるリプレイサー・ビショップが担当しています。","ENG":"The master brain, Bishop, is the ultimate overseer of the Qliphoth Replica Factor production.","TWN":"組合逆卡巴拉複製因子的究極功能，是由作為控制大腦的克隆．主教負責。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그녀가 바로 테라사이드 시스템의 중추입니다.","JPN":"彼女がまさにテラサイドシステムの中枢なんです。","ENG":"In short, Bishop is the backbone of System Terraside.","TWN":"她就是特拉賽德系統的中樞。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그렇다고 해도...... 차라리 불멸체 코어를 먼저 파괴하면 굳이 비숍과 싸울 필요는 없잖아?","JPN":"そ、そうだとしても……いっそのこと不滅体コアを先に破壊しちゃえば、\\nビショップと戦う必要はないよね？","ENG":"B-but why do we have to fight her when we can just destroy the Immortal System Core?","TWN":"就、就算是那樣……我們先破壞了不滅者核心，不就不用和克隆．大主教戰鬥了嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배의 말대로 데이터 수집이 멈추면 클리포트 레플리카 인자도 만들 수 없을 테니까.","JPN":"先輩の言うとおり、データ収集が止まれば、\\nレプリカ・クリフォト・ファクターを作ることもできないだろうから。","ENG":"Like you said, they won't be able to produce any more Qliphoth Replica Factors if they can't collect any more data.","TWN":"按照前輩所說的，只要停止數據收集的話，他們就無法製造逆卡巴拉複製因子了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아니요. 실질적으로 필요한 데이터는 이미 수집이 끝났을 겁니다.","JPN":"いいえ、実際に必要なデータは、すでに収集完了しているのだと思います。","ENG":"I don't think so. They should have finished collecting all the data they need by now.","TWN":"不是的。實際上，需要的資料已經收集完了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이제 와서 불멸체 코어를 파괴한다고 해도 그녀가 무사한 이상 클리포트 인자의 재배포를 막을 수는 없습니다.","JPN":"ここで不滅体コアを破壊するとしても、彼女が無事である限り、\\nクリフォト・ファクターの再配布を防ぐことはできません。","ENG":"Even if we were to destroy the Immortal System Core, we won't be able to stop them from redistributing the Qliphoth Factor as long as Bishop's alive.","TWN":"到了這個地步，就算破壞了不滅者核心，只要她平安無損，我們就無法阻止逆卡巴拉因子的再發送。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무엇보다...... 불멸체 코어가 어디에 있다고 생각하시죠, 미나 양?","JPN":"何より……不滅体コアはどこにあると思いますか、ミナさん？","ENG":"Most of all... Where do you think the Immortal System Core is, Mina?","TWN":"更重要的是……米娜小姐，妳有想過不滅者核心在哪裡嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어? 그러고 보니 이곳엔 딱히 특별한 설비가 안 보이는데......","JPN":"え？　そういえば、ここにはそれっぽい設備が見当たらないけど……","ENG":"Huh? Come to think of it, I don't see any proper apparatus or equipment here.","TWN":"咦？這麼一說，這裡好像沒看到什麼特別的設備……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 다른 곳에 있는 거야?","JPN":"まさか他所にあるの？","ENG":"Is it somewhere else?","TWN":"難道在其他地方嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};